// Capture status code and response time
const item = $input.first().json;
const now = new Date().toISOString();

// n8n puts full response details in the item when fullResponse: true
const statusCode = item.statusCode || 0;
const responseTimeMs = item.headers ? parseInt(item.headers['x-response-time'] || '0') : 0;

// Determine if the app is up
const isUp = statusCode === 200;

// Retrieve rolling stats from static data (persists across executions)
let stats = $getWorkflowStaticData('global');
if (!stats.totalChecks) {
  stats.totalChecks = 0;
  stats.totalDowntime = 0;
  stats.totalResponseTimeMs = 0;
  stats.lastDownAt = null;
  stats.consecutiveFailures = 0;
}

stats.totalChecks += 1;
if (!isUp) {
  stats.totalDowntime += 1;
  stats.consecutiveFailures = (stats.consecutiveFailures || 0) + 1;
  stats.lastDownAt = now;
} else {
  stats.consecutiveFailures = 0;
}
stats.totalResponseTimeMs += responseTimeMs;

const uptimePct = (((stats.totalChecks - stats.totalDowntime) / stats.totalChecks) * 100).toFixed(2);
const avgResponseMs = Math.round(stats.totalResponseTimeMs / stats.totalChecks);

return [{
  json: {
    timestamp: now,
    statusCode,
    isUp,
    responseTimeMs,
    uptimePct,
    avgResponseMs,
    totalChecks: stats.totalChecks,
    consecutiveFailures: stats.consecutiveFailures,
    url: 'https://demo.realworld.show'
  }
}];

// Wait 30 seconds and retry up to 3 times
const item = $input.first().json;

// Only retry if under 3 consecutive failures (first failure = retry)
if (item.consecutiveFailures < 3) {
  // Simulate wait - in production, this would use a Wait node
  return [{ json: { ...item, retry: true, retryAttempt: item.consecutiveFailures } }];
} else {
  return [{ json: { ...item, retry: false, confirmed: true } }];
}

const d = $input.first().json;

const statusEmoji = d.statusCode === 0 ? '🔌 Unreachable' : `HTTP ${d.statusCode}`;
const msg = [
  '🚨 **DOWNTIME ALERT — RealWorld App is DOWN**',
  '',
  `⏰ Time: ${d.timestamp}`,
  `🌐 URL: ${d.url}`,
  `❌ Status: ${statusEmoji}`,
  `🔁 Consecutive Failures: ${d.consecutiveFailures}`,
  `📊 Overall Uptime: ${d.uptimePct}%`,
  `⚡ Avg Response Time: ${d.avgResponseMs}ms`,
  '',
  '_Alert fired after 3 consecutive failed health checks._'
].join('\n');

return [{ json: { content: msg } }];

// App is up — check if response time is slow (> 2000ms)
const d = $input.first().json;

if (d.responseTimeMs > 2000) {
  const msg = [
    '⚠️ **SLOW RESPONSE — RealWorld App is degraded**',
    '',
    `⏰ Time: ${d.timestamp}`,
    `🌐 URL: ${d.url}`,
    `✅ Status: HTTP ${d.statusCode} (OK)`,
    `🐢 Response Time: ${d.responseTimeMs}ms (threshold: 2000ms)`,
    `📊 Uptime: ${d.uptimePct}%`
  ].join('\n');
  return [{ json: { content: msg, shouldAlert: true } }];
}

// All good – no alert needed
return [{ json: { content: null, shouldAlert: false, statusCode: d.statusCode, responseTimeMs: d.responseTimeMs, uptime: d.uptimePct } }];

// Daily summary — pull stats from static data
let stats = $getWorkflowStaticData('global');

const totalChecks = stats.totalChecks || 0;
const totalDowntime = stats.totalDowntime || 0;
const avgResponseMs = totalChecks > 0 ? Math.round((stats.totalResponseTimeMs || 0) / totalChecks) : 0;
const uptimePct = totalChecks > 0 ? (((totalChecks - totalDowntime) / totalChecks) * 100).toFixed(2) : '100.00';
const lastDownAt = stats.lastDownAt || 'Never';
const today = new Date().toLocaleDateString('en-IN', { timeZone: 'Asia/Kolkata' });

const msg = [
  `📋 **DAILY UPTIME REPORT — ${today}**`,
  '',
  `🌐 Monitored URL: https://demo.realworld.show`,
  `✅ Uptime: **${uptimePct}%**`,
  `🔍 Total Checks: ${totalChecks}`,
  `❌ Failed Checks: ${totalDowntime}`,
  `⚡ Avg Response Time: ${avgResponseMs}ms`,
  `🕐 Last Downtime: ${lastDownAt}`,
  '',
  `_Report generated at 08:00 IST. Next report in 24 hours._`
].join('\n');

// Reset daily counters (keep historical totals)
stats.lastDailyReport = new Date().toISOString();

return [{ json: { content: msg } }];

const error = $input.first().json;
const msg = [
  '⚠️ **UPTIME MONITOR – WORKFLOW ERROR**',
  `Node: ${error.execution?.lastNodeExecuted || 'Unknown'}`,
  `Error: ${error.execution?.error?.message || 'Unknown error'}`,
  `Time: ${new Date().toISOString()}`
].join('\n');
return [{ json: { content: msg } }];
